import React, { useState } from 'react';
import styled from 'styled-components';
import { useNavigate, Link } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { Button } from '../../components/Button';
import { Input } from '../../components/Input';
import { useAuth } from '../../contexts/AuthContext';
import { masks } from '../../utils/masks';
import { validators } from '../../utils/validators';

const Container = styled.div`
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  padding: 24px;
`;

const LoginCard = styled.div`
  background-color: white;
  border-radius: 32px;
  padding: 48px 40px;
  width: 100%;
  max-width: 450px;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
  transition: transform 0.3s ease;
  
  &:hover {
    transform: translateY(-5px);
  }
`;

const Title = styled.h2`
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-align: center;
  margin-bottom: 32px;
  font-size: 2rem;
  font-weight: 700;
`;

const Form = styled.form`
  display: flex;
  flex-direction: column;
  gap: 20px;
`;

const StyledLink = styled(Link)`
  color: #667eea;
  text-decoration: none;
  font-size: 0.9rem;
  text-align: center;
  display: block;
  margin-top: 24px;
  
  &:hover {
    text-decoration: underline;
  }
`;

const Divider = styled.div`
  display: flex;
  align-items: center;
  text-align: center;
  margin: 24px 0;
  
  &::before,
  &::after {
    content: '';
    flex: 1;
    border-bottom: 1px solid #e5e7eb;
  }
  
  span {
    margin: 0 16px;
    color: #9ca3af;
    font-size: 0.8rem;
  }
`;

const CpfLoginButton = styled(Button)`
  background: linear-gradient(135deg, #f59e0b 0%, #d97706 100%);
  
  &:hover {
    background: linear-gradient(135deg, #d97706 0%, #b45309 100%);
  }
`;

export const Login = () => {
  const navigate = useNavigate();
  const { login, loginSimulado } = useAuth();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [cpfLogin, setCpfLogin] = useState('');
  const [cpfLoading, setCpfLoading] = useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm();

  const onSubmit = async (data) => {
    setLoading(true);
    setError('');
    
    try {
      await login(data);
      navigate('/home');
    } catch (err) {
      setError('Credenciais invĂˇlidas. Tente novamente.');
    } finally {
      setLoading(false);
    }
  };

  const handleCpfLogin = async () => {
    if (!cpfLogin) {
      setError('Digite um CPF vĂˇlido');
      return;
    }
    
    const cpfLimpo = cpfLogin.replace(/\D/g, '');
    if (!validators.isValidCPF(cpfLimpo)) {
      setError('CPF invĂˇlido');
      return;
    }
    
    setCpfLoading(true);
    setError('');
    
    try {
      // Simular login por CPF
      await new Promise(resolve => setTimeout(resolve, 1000));
      loginSimulado();
      navigate('/home');
    } catch (err) {
      setError('CPF nĂŁo encontrado. FaĂ§a o cadastro primeiro.');
    } finally {
      setCpfLoading(false);
    }
  };

  const handleDemoAccess = () => {
    loginSimulado();
    navigate('/home');
  };

  const handleCpfChange = (e) => {
    setCpfLogin(masks.cpf(e.target.value));
  };

  return (
    <Container>
      <LoginCard>
        <Title>Login</Title>
        
        <Form onSubmit={handleSubmit(onSubmit)}>
          <Input
            label="Email"
            placeholder="seu@email.com"
            {...register('login', { 
              required: 'Campo obrigatĂłrio' 
            })}
            error={errors.login?.message}
          />

          <Input
            label="Senha"
            type="password"
            placeholder="Digite sua senha"
            {...register('senha', { 
              required: 'Campo obrigatĂłrio'
            })}
            error={errors.senha?.message}
          />

          {error && (
            <span style={{ color: '#ef4444', fontSize: '0.875rem', textAlign: 'center' }}>
              {error}
            </span>
          )}

          <Button type="submit" fullWidth disabled={loading} large>
            {loading ? 'Entrando...' : 'Entrar'}
          </Button>
        </Form>

        <Divider>
          <span>ou</span>
        </Divider>

        <div>
          <Input
            label="Login com CPF"
            placeholder="000.000.000-00"
            value={cpfLogin}
            onChange={handleCpfChange}
          />
          <CpfLoginButton 
            type="button" 
            fullWidth 
            onClick={handleCpfLogin}
            disabled={cpfLoading}
            style={{ marginTop: '12px' }}
          >
            {cpfLoading ? 'Verificando...' : 'đź”‘ Entrar com CPF'}
          </CpfLoginButton>
        </div>

        <Button type="button" fullWidth onClick={handleDemoAccess} outline style={{ marginTop: '16px' }}>
          âšˇ Acesso RĂˇpido (DemonstraĂ§ĂŁo)
        </Button>

        <StyledLink to="/register">
          NĂŁo tem uma conta? Cadastre-se
        </StyledLink>
      </LoginCard>
    </Container>
  );
};
